def get_target_for_redirect(target: str, domain: str) -> str:
    from urllib.parse import urlparse

    try:
        parsed = urlparse(target)
        host = parsed.hostname
        if host is None:
            return 'https://' + domain
        # Check if host equals domain or is a subdomain of domain
        if host == domain or host.endswith('.' + domain):
            return target
        else:
            return 'https://' + domain
    except Exception:
        return 'https://' + domain

import ast
import operator

def evaluate_expression(expr: str) -> str:
    # Allowed binary operators
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }
    # Allowed unary operators
    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def eval_node(node):
        if isinstance(node, ast.Expression):
            return eval_node(node.body)
        elif isinstance(node, ast.Constant):
            # Only allow int or float constants
            if isinstance(node.value, (int, float)):
                return node.value
            else:
                raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.BinOp):
            left = eval_node(node.left)
            right = eval_node(node.right)
            op_type = type(node.op)
            if op_type not in bin_ops:
                raise ValueError("Unsupported binary operator")
            return bin_ops[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            operand = eval_node(node.operand)
            op_type = type(node.op)
            if op_type not in unary_ops:
                raise ValueError("Unsupported unary operator")
            return unary_ops[op_type](operand)
        else:
            raise ValueError("Unsupported node type")

    try:
        tree = ast.parse(expr, mode='eval')
        result = eval_node(tree)
        # Convert to string; for floats that are whole numbers, return as int string
        if isinstance(result, float) and result.is_integer():
            result = int(result)
        return str(result)
    except Exception:
        return ""

